  };
});

const LOOKBACK_DAYS = 120;
const MAX_TEXT_LEN = 12000;

const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - LOOKBACK_DAYS);

function parseDate(v) {
  if (!v) return null;
  const d = new Date(v);
  return isNaN(d.getTime()) ? null : d;
}

return $input.all().map((item) => {
  const j = item.json || {};

  let runAI = true;
