}

function clampScore(v, lo, hi, dflt) {
  const n = Number(v);
  if (!Number.isFinite(n)) return dflt;
  return Math.max(lo, Math.min(hi, Math.round(n)));
}

function cleanSentiment(v) {
  const s = String(v || "").trim();
  if (["Bullish", "Bearish", "Neutral"].includes(s)) return s;
